
const express = require("express");
const mongoose = require("mongoose");
const bcrypt = require("bcryptjs");
const jwt = require("jsonwebtoken");
const cors = require("cors");

const app = express();
app.use(cors());
app.use(express.json({ limit: "10mb" }));

const PORT = process.env.PORT || 5000;
const JWT_SECRET = process.env.JWT_SECRET || "craverun_secret_key";
const MONGODB_URI =
"mongodb+srv://muthuvel6237_db_user:QjKFtxWQ02IbnAQy@cluster0.hdkspdb.mongodb.net/craverun?retryWrites=true&w=majority";

mongoose.connect(MONGODB_URI)
  .then(() => console.log("MongoDB connected"))
  .catch(err => console.log("MongoDB error:", err.message));

const userSchema = new mongoose.Schema({
  name: String,
  email: { type: String, unique: true },
  password: String,
  role: { type: String, enum: ["customer", "owner", "delivery", "admin"], default: "customer" },
  mobile: String,
  address: String
}, { timestamps: true });

const restaurantSchema = new mongoose.Schema({
  name: String,
  address: String,
  businessType: String,
  isOpen: { type: Boolean, default: true }
}, { timestamps: true });

const foodSchema = new mongoose.Schema({
  restaurant: { type: mongoose.Schema.Types.ObjectId, ref: "Restaurant" },
  name: String,
  category: String,
  price: Number,
  emoji: { type: String, default: "🍽️" },
  isAvailable: { type: Boolean, default: true }
}, { timestamps: true });

const orderSchema = new mongoose.Schema({
  customerName: String,
  mobile: String,
  address: String,
  items: [{ name: String, price: Number, qty: Number }],
  total: Number,
  paymentMethod: String,
  paymentStatus: { type: String, default: "paid_dummy" },
  status: { type: String, default: "placed" }
}, { timestamps: true });

const User = mongoose.model("User", userSchema);
const Restaurant = mongoose.model("Restaurant", restaurantSchema);
const Food = mongoose.model("Food", foodSchema);
const Order = mongoose.model("Order", orderSchema);

app.post("/api/register", async (req, res) => {
  try {
    const { name, email, password, role, mobile, address } = req.body;
    const hashed = await bcrypt.hash(password, 10);
    const user = await User.create({ name, email, password: hashed, role, mobile, address });
    res.json({ message: "Registered successfully", user });
  } catch (err) {
    res.status(400).json({ message: "Email already exists or invalid data" });
  }
});

app.post("/api/login", async (req, res) => {
  const { email, password } = req.body;
  const user = await User.findOne({ email });
  if (!user) return res.status(400).json({ message: "Invalid email" });
  const ok = await bcrypt.compare(password, user.password);
  if (!ok) return res.status(400).json({ message: "Invalid password" });
  const token = jwt.sign({ id: user._id, role: user.role, name: user.name }, JWT_SECRET);
  res.json({ token, user });
});

app.get("/api/foods", async (req, res) => {
  const foods = await Food.find().populate("restaurant").sort({ createdAt: -1 });
  res.json(foods);
});

app.post("/api/foods", async (req, res) => {
  const food = await Food.create(req.body);
  res.json(food);
});

app.get("/api/restaurants", async (req, res) => {
  const restaurants = await Restaurant.find().sort({ createdAt: -1 });
  res.json(restaurants);
});

app.post("/api/restaurants", async (req, res) => {
  const restaurant = await Restaurant.create(req.body);
  res.json(restaurant);
});

app.put("/api/restaurants/:id/status", async (req, res) => {
  const restaurant = await Restaurant.findById(req.params.id);
  restaurant.isOpen = !restaurant.isOpen;
  await restaurant.save();
  res.json(restaurant);
});

app.post("/api/orders", async (req, res) => {
  const order = await Order.create(req.body);
  res.json({ message: "Dummy payment successful. Order placed.", orderId: "CR" + order._id, order });
});

app.get("/api/orders", async (req, res) => {
  const orders = await Order.find().sort({ createdAt: -1 });
  res.json(orders);
});

app.post("/api/seed", async (req, res) => {
  await Restaurant.deleteMany();
  await Food.deleteMany();

  const r1 = await Restaurant.create({ name: "CraveRun Cafe", address: "Main Road", businessType: "Cafe / Snacks / Drinks", isOpen: true });
  const r2 = await Restaurant.create({ name: "Pizza House", address: "City Center", businessType: "Veg & Non Veg Both", isOpen: true });
  const r3 = await Restaurant.create({ name: "South Cafe", address: "Market Street", businessType: "Veg Only", isOpen: false });

  await Food.create([
    { restaurant: r1._id, name: "Cheese Burger", category: "Snacks", price: 149, emoji: "🍔" },
    { restaurant: r2._id, name: "Farmhouse Pizza", category: "Veg", price: 299, emoji: "🍕" },
    { restaurant: r2._id, name: "Chicken Biryani", category: "Non Veg", price: 220, emoji: "🍛" },
    { restaurant: r3._id, name: "Masala Dosa", category: "Veg", price: 90, emoji: "🥞" }
  ]);

  res.json({ message: "Sample data added" });
});

const logo = "data:image/png;base64,";

app.get("/", (req, res) => {
  res.send(`<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>CraveRun MERN Single File</title>
<script src="https://unpkg.com/react@18/umd/react.development.js"></script>
<script src="https://unpkg.com/react-dom@18/umd/react-dom.development.js"></script>
<script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>
<style>
*{margin:0;padding:0;box-sizing:border-box;font-family:Arial,sans-serif}body{background:#f8f9fa;color:#222}:root{--orange:#ff5a00;--red:#c1121f}
header{position:sticky;top:0;z-index:10;background:#fff;display:flex;justify-content:space-between;align-items:center;padding:12px 7%;box-shadow:0 8px 25px #0002}
.logo{display:flex;align-items:center;gap:10px;font-size:30px;font-weight:900}.logo img{width:70px;height:70px;object-fit:contain;border-radius:14px}.logo span{color:var(--orange)}
nav a{margin:0 10px;text-decoration:none;color:#222;font-weight:700}.btn{background:var(--orange);color:white;border:0;padding:12px 22px;border-radius:30px;font-weight:800;cursor:pointer}
section{padding:45px 7%}.hero{display:grid;grid-template-columns:1fr 1fr;gap:35px;align-items:center}.hero h1{font-size:52px;line-height:1.1}.hero h1 span{color:var(--orange)}.hero p{font-size:18px;color:#555;margin:18px 0}
.search{display:flex;background:white;padding:10px;border-radius:40px;box-shadow:0 12px 35px #0002}.search input{flex:1;border:0;outline:0;padding:15px;font-size:16px}
.hero-img{background:linear-gradient(135deg,#ff5a00,#ff9800);border-radius:45px;text-align:center;padding:35px}.hero-img img{width:100%;max-width:420px;background:white;border-radius:35px;padding:15px}
.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:25px}.card,.box,.form{background:white;border-radius:25px;box-shadow:0 12px 35px #0001;overflow:hidden;position:relative}.food-img{height:170px;display:flex;align-items:center;justify-content:center;font-size:78px;background:#fff3eb}.body{padding:18px}.price{color:var(--orange);font-size:21px;font-weight:900;margin:12px 0}.row{display:flex;justify-content:space-between;align-items:center}.plus{width:42px;height:42px;border-radius:50%;background:var(--orange);color:white;border:0;font-size:25px;cursor:pointer}.badge{position:absolute;top:12px;left:12px;background:green;color:white;padding:7px 14px;border-radius:20px;font-weight:800;font-size:13px}.closed{background:var(--red)}
.forms{display:grid;grid-template-columns:1fr 1fr;gap:25px}.form{padding:25px}.form h2,.box h3{color:var(--orange);margin-bottom:14px}input,select,textarea{width:100%;padding:14px;margin:8px 0;border:1px solid #ddd;border-radius:14px;outline:0}.cart{position:fixed;right:-420px;top:0;width:380px;height:100%;background:white;z-index:50;padding:25px;box-shadow:-12px 0 35px #0003;transition:.4s;overflow:auto}.cart.active{right:0}.cart-item{display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid #eee;padding:14px 0}.qty{display:flex;gap:10px;align-items:center}.qty button{background:var(--orange);color:white;border:0;width:28px;height:28px;border-radius:50%;font-weight:900}footer{background:#111;color:white;text-align:center;padding:35px;margin-top:40px}footer img{width:90px;background:white;border-radius:18px;padding:6px}
@media(max-width:1024px){.grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:768px){nav{display:none}.hero,.forms{grid-template-columns:1fr;text-align:center}.hero h1{font-size:36px}.grid{grid-template-columns:1fr}.cart{width:100%;right:-100%}}
</style>
</head>
<body>
<div id="root"></div>
<script type="text/babel">
const logo = "${logo}";

function App(){
 const [foods,setFoods]=React.useState([]);
 const [restaurants,setRestaurants]=React.useState([]);
 const [cart,setCart]=React.useState([]);
 const [open,setOpen]=React.useState(false);
 const [search,setSearch]=React.useState("");
 const [msg,setMsg]=React.useState("");

 React.useEffect(()=>{ load(); },[]);

 async function load(){
  const f=await fetch("/api/foods").then(r=>r.json());
  const r=await fetch("/api/restaurants").then(r=>r.json());
  setFoods(f); setRestaurants(r);
 }

 async function seed(){ await fetch("/api/seed",{method:"POST"}); load(); }

 function addToCart(food){
  if(food.restaurant && !food.restaurant.isOpen){ alert("This restaurant is closed today"); return; }
  setCart(c=>{
    let x=[...c];
    let old=x.find(i=>i.name===food.name);
    if(old) old.qty++;
    else x.push({name:food.name,price:food.price,qty:1});
    return x;
  });
  setOpen(true);
 }

 function inc(i){ setCart(c=>c.map((x,k)=>k===i?{...x,qty:x.qty+1}:x)); }
 function dec(i){ setCart(c=>c.map((x,k)=>k===i?{...x,qty:x.qty-1}:x).filter(x=>x.qty>0)); }

 const total=cart.reduce((s,i)=>s+i.price*i.qty,0);

 async function dummyPay(){
  if(total<=0){ alert("Please add food to cart first"); return; }
  const order=await fetch("/api/orders",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify({customerName:"Demo Customer",mobile:"9999999999",address:"Demo Address",items:cart,total,paymentMethod:"Dummy Payment"})
  }).then(r=>r.json());

  alert("✅ Dummy Payment Successful\\nOrder ID: "+order.orderId+"\\nAmount: ₹"+total);
  setCart([]); setOpen(false);
 }

 async function saveFood(e){
  e.preventDefault();
  const fd=new FormData(e.target);
  await fetch("/api/foods",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify({name:fd.get("name"),price:Number(fd.get("price")),category:fd.get("category"),emoji:fd.get("emoji"),restaurant:fd.get("restaurant")})
  });
  e.target.reset(); setMsg("Food saved successfully"); load();
 }

 async function saveRestaurant(e){
  e.preventDefault();
  const fd=new FormData(e.target);
  await fetch("/api/restaurants",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify({name:fd.get("name"),address:fd.get("address"),businessType:fd.get("businessType"),isOpen:true})
  });
  e.target.reset(); setMsg("Restaurant saved successfully"); load();
 }

 async function toggle(id){ await fetch("/api/restaurants/"+id+"/status",{method:"PUT"}); load(); }

 const shown=foods.filter(f=>(f.name+" "+(f.restaurant?.name||"")).toLowerCase().includes(search.toLowerCase()));

 return <div>
  <header>
    <div className="logo"><img src={logo}/><div>crave<span>run</span></div></div>
    <nav><a href="#home">Home</a><a href="#foods">Foods</a><a href="#owner">Owner</a><a href="#payment">Payment</a></nav>
    <button className="btn" onClick={()=>setOpen(true)}>Cart</button>
  </header>

  <section className="hero" id="home">
    <div>
      <h1>Choose Your Favourite <span>Food</span></h1>
      <p>MERN food delivery app with React, Node, Express and MongoDB.</p>
      <div className="search"><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search burger, pizza, biryani, cafe..."/><button className="btn">Search</button></div>
      <br/><button className="btn" onClick={seed}>Add Sample Data</button>
    </div>
    <div className="hero-img"><img src={logo}/></div>
  </section>

  <section id="foods">
    <h2>Popular Foods</h2><br/>
    <div className="grid">
      {shown.map(f=>
        <div className="card" key={f._id}>
          <span className={"badge "+(f.restaurant?.isOpen?"":"closed")}>{f.restaurant?.isOpen?"OPEN":"CLOSED"}</span>
          <div className="food-img">{f.emoji}</div>
          <div className="body">
            <h3>{f.name}</h3><p>{f.restaurant?.name}</p>
            <div className="row"><div className="price">₹{f.price}</div><button className="plus" onClick={()=>addToCart(f)}>+</button></div>
          </div>
        </div>
      )}
    </div>
  </section>

  <section id="owner">
    <h2>Restaurant / Cafe Owner Panel</h2><br/>
    <div className="forms">
      <form className="form" onSubmit={saveRestaurant}>
        <h2>Add Restaurant</h2>
        <input name="name" placeholder="Restaurant / Cafe Name"/>
        <input name="address" placeholder="Address"/>
        <select name="businessType"><option>Veg Only</option><option>Non Veg Only</option><option>Veg & Non Veg Both</option><option>Cafe / Snacks / Drinks</option><option>Bakery</option></select>
        <button className="btn">Save Restaurant</button>
      </form>
      <form className="form" onSubmit={saveFood}>
        <h2>Add Food</h2>
        <select name="restaurant">{restaurants.map(r=><option value={r._id} key={r._id}>{r.name}</option>)}</select>
        <input name="name" placeholder="Food Name"/>
        <input name="price" type="number" placeholder="Price"/>
        <input name="emoji" placeholder="Emoji e.g. 🍔"/>
        <select name="category"><option>Veg</option><option>Non Veg</option><option>Snacks</option><option>Drinks</option><option>Cafe Items</option></select>
        <button className="btn">Save Food</button>
        <p>{msg}</p>
      </form>
    </div>
    <br/>
    <div className="grid">
      {restaurants.map(r=>
        <div className="box" key={r._id}>
          <h3>{r.name}</h3>
          <p>{r.businessType}</p>
          <p>{r.address}</p>
          <p style={{color:r.isOpen?"green":"#c1121f",fontWeight:"900"}}>{r.isOpen?"OPEN NOW":"CLOSED TODAY"}</p>
          <button className="btn" onClick={()=>toggle(r._id)}>Change Status</button>
        </div>
      )}
    </div>
  </section>

  <section id="payment">
    <h2>Dummy Payment</h2><br/>
    <div className="grid">
      <div className="box"><h3>📱 UPI Dummy</h3><p>No real money</p></div>
      <div className="box"><h3>💳 Card Dummy</h3><p>Always successful</p></div>
      <div className="box"><h3>💵 COD</h3><p>Cash on delivery</p></div>
      <div className="box"><h3>✅ Order</h3><p>Saved in MongoDB</p></div>
    </div>
  </section>

  <div className={"cart "+(open?"active":"")}>
    <span style={{float:"right",fontSize:"28px",cursor:"pointer"}} onClick={()=>setOpen(false)}>×</span>
    <h2>Your Cart</h2>
    {cart.map((i,k)=>
      <div className="cart-item" key={k}>
        <div><b>{i.name}</b><br/><small>₹{i.price} x {i.qty}</small></div>
        <div className="qty"><button onClick={()=>dec(k)}>-</button><b>{i.qty}</b><button onClick={()=>inc(k)}>+</button></div>
      </div>
    )}
    <h3>Total: ₹{total}</h3><br/>
    <select><option>Dummy UPI</option><option>Dummy Card</option><option>Cash On Delivery</option></select><br/><br/>
    <button className="btn" style={{width:"100%"}} onClick={dummyPay}>Dummy Pay / Place Order</button>
  </div>

  <footer><img src={logo}/><h2>crave<span style={{color:"#ff5a00"}}>run</span></h2><p>Good Food. Fast Delivery.</p></footer>
 </div>
}
ReactDOM.createRoot(document.getElementById("root")).render(<App/>);
</script>
</body>
</html>`);
});

app.listen(PORT, () => console.log("CraveRun running on http://127.0.0.1:" + PORT));
